steps.args:
var hier = JSON.parse(results[0] || '{}');
var allObjs = hier.objects || [];

// Build parentMap
var parentMap = {};
for (var i = 0; i < allObjs.length; i++) {
  var o = allObjs[i];
  if (o.children) {
    for (var j = 0; j < o.children.length; j++) {
      parentMap[o.children[j]] = o.id;
    }
  }
}

// Bones — deduplicated
var bones = JSON.parse(results[1] || '{}').objects || [];
var rootBones = JSON.parse(results[2] || '{}').objects || [];
var boneIdsSeen = {};
var boneIds = [];
bones.concat(rootBones).forEach(function(b) {
  if (!boneIdsSeen[b.id]) { boneIdsSeen[b.id] = true; boneIds.push(b.id); }
});

// Vertices
var vertexTypes = ['CubicMirroredVertex','CubicDetachedVertex','CubicAsymmetricVertex','StraightVertex'];
var vertexIds = allObjs.filter(function(o) {
  return o.types && o.types.some(function(t){ return vertexTypes.indexOf(t) >= 0; });
}).map(function(v){ return v.id; });

// Skin object — its children array IS the ordered tendon list
var skinObj = null;
for (var i = 0; i < allObjs.length; i++) {
  if (allObjs[i].types && allObjs[i].types.indexOf('Skin') >= 0) { skinObj = allObjs[i]; break; }
}
var skinTendonOrder = skinObj ? (skinObj.children || []) : [];
// tendonIds in Skin children order (this determines bone indices for weight encoding)
var tendonIds = skinTendonOrder;

// Weight/CubicWeight objects — children of vertices
var weightTypes = ['Weight', 'CubicWeight'];
var weightObjIds = [];
var vertexToWeightMap = {};
var cubicWeightSet = {};
for (var i = 0; i < allObjs.length; i++) {
  var o = allObjs[i];
  if (o.types && o.types.some(function(t){ return weightTypes.indexOf(t) >= 0; })) {
    weightObjIds.push(o.id);
    var pid = parentMap[o.id];
    if (pid) vertexToWeightMap[pid] = o.id;
    if (o.types.indexOf('CubicWeight') >= 0) cubicWeightSet[o.id] = true;
  }
}

// Find Shape that contains the skinned path
// Skin parent = PointsPath, PointsPath parent = Shape
var skinParent = skinObj ? parentMap[skinObj.id] : null; // PointsPath
var shapeId = skinParent ? parentMap[skinParent] : null; // Shape

// Track which bones are RootBones (they use absolute x/y, not parent-relative)
var rootBoneSet = {};
allObjs.forEach(function(o) {
  if (o.types && o.types.indexOf('RootBone') >= 0) rootBoneSet[o.id] = true;
});

setVar('boneIds', JSON.stringify(boneIds));
setVar('vertexIds', JSON.stringify(vertexIds));
setVar('tendonIds', JSON.stringify(tendonIds));
setVar('weightObjIds', JSON.stringify(weightObjIds));
setVar('vertexToWeightMap', JSON.stringify(vertexToWeightMap));
setVar('cubicWeightSet', JSON.stringify(cubicWeightSet));
setVar('rootBoneSet', JSON.stringify(rootBoneSet));
setVar('shapeId', shapeId || '');
setVar('boneCount', String(boneIds.length));
setVar('vertexCount', String(vertexIds.length));
setVar('tendonCount', String(tendonIds.length));

var boneKeys = JSON.parse(results[4] || '{}').properties || {};
var vertexKeys = JSON.parse(results[5] || '{}').properties || {};
var tendonKeys = JSON.parse(results[6] || '{}').properties || {};

// For bones we need: x(13), y(14), rotation(15), length(781 or 'length'), parentId(5)
// Build query: for each bone, get the keys we care about
var boneValQuery = {};
for (var bid in boneKeys) {
  var keys = boneKeys[bid];
  var interesting = [];
  // Grab all numeric key values — we'll read them all and filter by name later
  for (var name in keys) {
    if (typeof keys[name] === 'number') interesting.push(keys[name]);
  }
  boneValQuery[bid] = interesting;
}

// For vertices we need: x(24 or 13), y(25 or 14)
var vertexValQuery = {};
for (var vid in vertexKeys) {
  var keys = vertexKeys[vid];
  var interesting = [];
  for (var name in keys) {
    if (typeof keys[name] === 'number') interesting.push(keys[name]);
  }
  vertexValQuery[vid] = interesting;
}

// For tendons we need all props
var tendonValQuery = {};
for (var tid in tendonKeys) {
  var keys = tendonKeys[tid];
  var interesting = [];
  for (var name in keys) {
    if (typeof keys[name] === 'number') interesting.push(keys[name]);
  }
  tendonValQuery[tid] = interesting;
}

// Also query the shape's transform (x/y) — add to boneValQuery since it uses same key space
var shapeId = vars.shapeId;
if (shapeId) {
  boneValQuery[shapeId] = [13, 14, 15, 16, 17, 24, 25, 5, 6, 130];
}

setVar('boneValQuery', JSON.stringify(boneValQuery));
setVar('vertexValQuery', JSON.stringify(vertexValQuery));
setVar('tendonValQuery', JSON.stringify(tendonValQuery));
setVar('boneKeysMap', JSON.stringify(boneKeys));
setVar('vertexKeysMap', JSON.stringify(vertexKeys));
setVar('tendonKeysMap', JSON.stringify(tendonKeys));

var boneKeysMap = JSON.parse(vars.boneKeysMap);
var vertexKeysMap = JSON.parse(vars.vertexKeysMap);
var tendonKeysMap = JSON.parse(vars.tendonKeysMap);
var boneVals = JSON.parse(results[8] || '{}').values || {};
var vertexVals = JSON.parse(results[9] || '{}').values || {};
var tendonVals = JSON.parse(results[10] || '{}').values || {};

function getVal(valsMap, keysMap, objId, propName) {
  var keys = keysMap[objId];
  if (!keys) return undefined;
  var keyNum = keys[propName];
  if (keyNum === undefined) return undefined;
  var objVals = valsMap[objId];
  return objVals ? objVals[String(keyNum)] : undefined;
}

// Build boneId -> tendonIndex from Skin.children order (already stored in tendonIds)
// tendonIds = Skin.children in order; each tendon has boneid (key 95) in tendonVals
var tendonIds = JSON.parse(vars.tendonIds);
var boneToIndex = {};
for (var ti = 0; ti < tendonIds.length; ti++) {
  var tid = tendonIds[ti];
  var boneId = tendonVals[tid] ? tendonVals[tid]['95'] : null;
  if (boneId) boneToIndex[boneId] = ti;
}

// Build parent map (bone parentage) from boneVals parentId (key 5)
var boneIds = JSON.parse(vars.boneIds);
var boneParentMap = {};
for (var bi = 0; bi < boneIds.length; bi++) {
  var bid = boneIds[bi];
  var bvals = boneVals[bid] || {};
  var pid = bvals['5']; // parentId key
  boneParentMap[bid] = pid;
}

// Build bone local data for parent walk-up
var boneLocal = {};
for (var bi = 0; bi < boneIds.length; bi++) {
  var bid = boneIds[bi];
  var ll = getVal(boneVals, boneKeysMap, bid, 'length') || 0;
  boneLocal[bid] = { length: ll, parentId: boneParentMap[bid] };
}

// Use tendon bind-pose transforms (tx/ty/xx/yx) as authoritative world positions
// This avoids errors from computing RootBone child positions from scratch
// Tendon matrix: xx=cos(rot), yx=-sin(rot), so tip = (tx+xx*len, ty-yx*len)
var segments = [];
for (var bi = 0; bi < boneIds.length; bi++) {
  var bid = boneIds[bi];
  var tIdx = boneToIndex[bid];
  if (tIdx === undefined) continue;
  var tid = tendonIds[tIdx];
  var tv = tendonVals[tid];
  if (!tv) continue;
  var ll = boneLocal[bid].length;
  if (ll <= 0) continue;
  var tx = tv['100'] || 0, ty = tv['101'] || 0;
  var xx = tv['96'] || 0, yx = tv['97'] || 0;
  var tipX = tx + xx * ll;
  var tipY = ty - yx * ll;
  segments.push({ id: bid, ax: tx, ay: ty, bx: tipX, by: tipY });
}

// Get shape world offset to transform vertex local coords to world coords
var shapeId = vars.shapeId;
var shapeVals = shapeId ? (boneVals[shapeId] || {}) : {};
var shapeX = 0, shapeY = 0;
// Try common x/y property keys: 13, 24, or named
for (var k in shapeVals) {
  var kn = parseInt(k);
  if (kn === 13 || kn === 24) shapeX = shapeVals[k] || 0;
  if (kn === 14 || kn === 25) shapeY = shapeVals[k] || 0;
}

var vertexIds = JSON.parse(vars.vertexIds);
var vertexPositions = [];
for (var vi = 0; vi < vertexIds.length; vi++) {
  var vid = vertexIds[vi];
  var vx = getVal(vertexVals, vertexKeysMap, vid, 'x') || 0;
  var vy = getVal(vertexVals, vertexKeysMap, vid, 'y') || 0;
  vertexPositions.push({ id: vid, x: vx + shapeX, y: vy + shapeY });
}

function pointToSegmentDist(px, py, ax, ay, bx, by) {
  var dx = bx - ax, dy = by - ay;
  var lenSq = dx*dx + dy*dy;
  if (lenSq === 0) return { dist: Math.sqrt((px-ax)*(px-ax)+(py-ay)*(py-ay)), t: 0 };
  var t = Math.max(0, Math.min(1, ((px-ax)*dx + (py-ay)*dy) / lenSq));
  var projX = ax + t*dx, projY = ay + t*dy;
  return { dist: Math.sqrt((px-projX)*(px-projX)+(py-projY)*(py-projY)), t: t };
}

// For each vertex, find nearest bone segment → compute weights
var assignments = {};
for (var vi = 0; vi < vertexPositions.length; vi++) {
  var v = vertexPositions[vi];
  var bestDist = Infinity, bestSeg = null, bestT = 0;
  for (var si = 0; si < segments.length; si++) {
    var seg = segments[si];
    var r = pointToSegmentDist(v.x, v.y, seg.ax, seg.ay, seg.bx, seg.by);
    if (r.dist < bestDist) { bestDist = r.dist; bestSeg = seg; bestT = r.t; }
  }
  if (bestSeg) {
    var w = {};
    // Walk up to find parent bone that has a tendon
    var parentBoneId = boneLocal[bestSeg.id] ? boneLocal[bestSeg.id].parentId : null;
    // Find nearest ancestor that has a tendon index
    while (parentBoneId && boneToIndex[parentBoneId] === undefined && boneLocal[parentBoneId]) {
      parentBoneId = boneLocal[parentBoneId].parentId;
    }
    var parentHasTendon = parentBoneId && boneToIndex[parentBoneId] !== undefined;
    if (parentHasTendon) {
      var tipW = Math.round(bestT * 100);
      var baseW = 100 - tipW;
      if (tipW > 0) w[bestSeg.id] = tipW;
      if (baseW > 0) w[parentBoneId] = baseW;
    } else {
      w[bestSeg.id] = 100;
    }
    assignments[v.id] = w;
  }
}

// Build set_property_values payload targeting Weight/CubicWeight objects
// keys 102 = values (weight amounts), 103 = indices (bone index in Skin.children order)
var vertexToWeightMap = JSON.parse(vars.vertexToWeightMap);
var propValues = {};
var updated = 0;
var debugLines = [];

for (var vi = 0; vi < vertexIds.length; vi++) {
  var vid = vertexIds[vi];
  var weightObjId = vertexToWeightMap[vid];
  if (!weightObjId) { debugLines.push(vid + ': no Weight child'); continue; }
  var boneWeights = assignments[vid];
  if (!boneWeights) { debugLines.push(vid + ': no assignment'); continue; }

  var idxBytes = [], valBytes = [];
  for (var boneId in boneWeights) {
    var idx = boneToIndex[boneId];
    if (idx === undefined) { debugLines.push('boneId ' + boneId + ' not in boneToIndex'); continue; }
    var w = boneWeights[boneId];
    if (w <= 0) continue;
    idxBytes.push(idx + 1);
    valBytes.push(Math.round(w * 255 / 100));
  }

  if (idxBytes.length > 0) {
    var packedIdx = 0, packedVal = 0;
    for (var b = 0; b < idxBytes.length; b++) {
      packedIdx = (packedIdx << 8) | (idxBytes[b] & 0xFF);
      packedVal = (packedVal << 8) | (valBytes[b] & 0xFF);
    }
    var cubicWeightSet = JSON.parse(vars.cubicWeightSet || '{}');
    var props = { '102': packedVal, '103': packedIdx };
    if (cubicWeightSet[weightObjId]) {
      props['110'] = packedVal;
      props['111'] = packedIdx;
      props['112'] = packedVal;
      props['113'] = packedIdx;
    }
    propValues[weightObjId] = props;
    updated++;
    debugLines.push(vid + '->' + weightObjId + (cubicWeightSet[weightObjId] ? ' [cubic]' : '') + ' idx=' + packedIdx + ' val=' + packedVal);
  }
}

setVar('skinPayload', JSON.stringify({ propertyValues: propValues }));
setVar('updatedWeights', String(updated));
setVar('segmentCount', String(segments.length));
setVar('boneToIndex', JSON.stringify(boneToIndex));
setVar('assignmentsSummary', JSON.stringify(
  Object.keys(assignments).map(function(vid) { return vid + ': ' + JSON.stringify(assignments[vid]); }).join('\n')
));
setVar('weightDebug', debugLines.join('\n'));
